-- V12__expand_catalog.sql
-- Soft-delete stray test products created through an ad-hoc admin API test,
-- and expand the catalog from 4 to 8 real products per category.

UPDATE products SET is_deleted = true, is_active = false, deleted_date = now()
WHERE ornament_id IN ('ORN-000021', 'ORN-000022');

