    ('ORN-000024', 'Baroque Pearl Statement Necklace', 'baroque-pearl-statement-necklace', 'Bold baroque pearl choker with gold chain.', 'A statement choker featuring irregular baroque-style pearls set along a warm gold-plated chain.', 6900.00, 5800.00, 'GOLD_PLATED', 40.00, (SELECT id FROM categories WHERE slug = 'necklaces'), (SELECT id FROM sub_categories WHERE slug = 'chokers-necklaces'), true, true, 'IN_STOCK', 'Baroque Pearl Statement Necklace | Sri Sai Fashion Jewellery', 'Bold baroque pearl statement choker necklace.', 'system', 'system'),
