    ('ORN-000029', 'Emerald Stud Earrings', 'emerald-stud-earrings', 'Gold-plated studs with emerald-green stone.', 'Petite stud earrings set with a faceted emerald-green stone, finished in imitation gold.', 1700.00, NULL, 'GOLD_PLATED', 5.50, (SELECT id FROM categories WHERE slug = 'earrings'), (SELECT id FROM sub_categories WHERE slug = 'studs'), true, false, 'IN_STOCK', 'Emerald Stud Earrings | Sri Sai Fashion Jewellery', 'Gold-plated stud earrings with emerald-green stone.', 'system', 'system'),
    ('ORN-000030', 'Heart Diamond Stud Earrings', 'heart-diamond-stud-earrings', 'Heart-shaped CZ stud earrings.', 'Sweet heart-shaped stud earrings set with sparkling cubic zirconia stones.', 2100.00, 1850.00, 'CZ', 4.20, (SELECT id FROM categories WHERE slug = 'earrings'), (SELECT id FROM sub_categories WHERE slug = 'studs'), true, false, 'IN_STOCK', 'Heart Diamond Stud Earrings | Sri Sai Fashion Jewellery', 'Heart-shaped cubic zirconia stud earrings.', 'system', 'system'),

