    ('ORN-000033', 'Turquoise Charm Bangle', 'turquoise-charm-bangle', 'Silver-finish bangle with turquoise beads.', 'A silver-tone bangle accented with turquoise-hued beads for a pop of colour.', 2200.00, NULL, 'SILVER', 20.00, (SELECT id FROM categories WHERE slug = 'bangles'), (SELECT id FROM sub_categories WHERE slug = 'charm-bangles'), true, false, 'IN_STOCK', 'Turquoise Charm Bangle | Sri Sai Fashion Jewellery', 'Silver-finish bangle with turquoise bead accents.', 'system', 'system'),
    ('ORN-000034', 'Beaded Stretch Bangle Stack', 'beaded-stretch-bangle-stack', 'Set of beaded stretch bangles.', 'A stretchable stack of beaded bangles in a warm brass tone, easy to layer with other pieces.', 1600.00, NULL, 'BRASS', 15.00, (SELECT id FROM categories WHERE slug = 'bangles'), (SELECT id FROM sub_categories WHERE slug = 'charm-bangles'), true, false, 'IN_STOCK', 'Beaded Stretch Bangle Stack | Sri Sai Fashion Jewellery', 'Set of beaded stretch bangles in brass tone.', 'system', 'system'),

    ('ORN-000035', 'Diamond Halo Statement Ring', 'diamond-halo-statement-ring', 'CZ halo statement ring.', 'A striking statement ring featuring a halo of cubic zirconia stones around a central solitaire.', 3200.00, 2700.00, 'CZ', 6.50, (SELECT id FROM categories WHERE slug = 'rings'), (SELECT id FROM sub_categories WHERE slug = 'cocktail-rings'), true, true, 'IN_STOCK', 'Diamond Halo Statement Ring | Sri Sai Fashion Jewellery', 'Cubic zirconia halo statement ring.', 'system', 'system'),
