    ('ORN-000038', 'Stackable Ring Set', 'stackable-ring-set', 'Set of three slim stacking rings.', 'A set of three slim rings in a rose-gold-plated finish, designed to be worn stacked or separately.', 2300.00, 1950.00, 'ROSE_GOLD_PLATED', 6.00, (SELECT id FROM categories WHERE slug = 'rings'), (SELECT id FROM sub_categories WHERE slug = 'bands'), true, false, 'IN_STOCK', 'Stackable Ring Set | Sri Sai Fashion Jewellery', 'Set of three slim rose-gold-plated stacking rings.', 'system', 'system'),

    ('ORN-000039', 'Antique Gold Bridal Set', 'antique-gold-bridal-set', 'Complete antique-finish bridal necklace set.', 'A complete bridal necklace and earring set finished in an antique-gold plating for a heritage look.', 16500.00, 14200.00, 'GOLD_PLATED', 105.00, (SELECT id FROM categories WHERE slug = 'bridal-sets'), (SELECT id FROM sub_categories WHERE slug = 'necklace-sets'), true, true, 'IN_STOCK', 'Antique Gold Bridal Set | Sri Sai Fashion Jewellery', 'Complete antique-finish gold bridal necklace set.', 'system', 'system'),
