    ('ORN-000041', 'Ruby Maang Tikka Set', 'ruby-maang-tikka-set', 'Ruby-accented maang tikka with earrings.', 'A matching maang tikka and earring set with ruby-red stone accents, finished in imitation gold.', 10200.00, 8700.00, 'GOLD_PLATED', 50.00, (SELECT id FROM categories WHERE slug = 'bridal-sets'), (SELECT id FROM sub_categories WHERE slug = 'maang-tikka-sets'), true, true, 'IN_STOCK', 'Ruby Maang Tikka Set | Sri Sai Fashion Jewellery', 'Ruby-accented maang tikka and earring bridal set.', 'system', 'system'),
