    ('ORN-000027', '/images/products/earrings/vintage-drop-earrings.jpg'),
    ('ORN-000028', '/images/products/earrings/traditional-gold-danglers.jpg'),
    ('ORN-000029', '/images/products/earrings/emerald-stud-earrings.jpg'),
