    ('ORN-000031', '/images/products/bangles/polished-gold-bangle-pair.jpg'),
    ('ORN-000032', '/images/products/bangles/classic-stackable-bangle-set.jpg'),
    ('ORN-000033', '/images/products/bangles/turquoise-charm-bangle.jpg'),
    ('ORN-000034', '/images/products/bangles/beaded-stretch-bangle-stack.jpg'),
    ('ORN-000035', '/images/products/rings/diamond-halo-statement-ring.jpg'),
    ('ORN-000036', '/images/products/rings/emerald-cocktail-ring.jpg'),
